7534   unsigned N = 1;
7535   Type *EltTy = T;
7536 
7537   while (isa<StructType, ArrayType, FixedVectorType>(EltTy)) {
7538     if (auto *ST = dyn_cast<StructType>(EltTy)) {
7539       // Check that struct is homogeneous.
7540       for (const auto *Ty : ST->elements())
7541         if (Ty != *ST->element_begin())
7542           return 0;
